// Minimal Chart stub - draws simple line charts without CDN
class Chart {
  constructor(ctx, config) {
    this.ctx = ctx;
    this.config = config;
    this._draw();
  }
  destroy() {
    const canvas = this.ctx.canvas || this.ctx;
    const c = canvas.getContext('2d');
    if (c) c.clearRect(0, 0, canvas.width, canvas.height);
  }
  _draw() {
    const canvas = this.ctx.canvas || this.ctx;
    if (!canvas) return;
    const c = canvas.getContext('2d');
    const w = canvas.width = canvas.offsetWidth || 200;
    const h = canvas.height = canvas.offsetHeight || 120;
    const data = this.config?.data?.datasets?.[0]?.data || [];
    const labels = this.config?.data?.labels || [];
    const color = this.config?.data?.datasets?.[0]?.borderColor || '#6c63ff';
    if (!data.length) return;
    c.clearRect(0, 0, w, h);
    const pad = {t:10, r:10, b:28, l:36};
    const cw = w - pad.l - pad.r;
    const ch = h - pad.t - pad.b;
    const min = Math.min(...data) * 0.9;
    const max = Math.max(...data) * 1.1 || 1;
    const xStep = cw / Math.max(data.length - 1, 1);
    // Grid
    c.strokeStyle = 'rgba(255,255,255,0.05)';
    c.lineWidth = 1;
    for (let i = 0; i <= 3; i++) {
      const y = pad.t + ch - (ch * i / 3);
      c.beginPath(); c.moveTo(pad.l, y); c.lineTo(pad.l + cw, y); c.stroke();
    }
    // Fill
    c.beginPath();
    data.forEach((v, i) => {
      const x = pad.l + i * xStep;
      const y = pad.t + ch - ((v - min) / (max - min) * ch);
      i === 0 ? c.moveTo(x, y) : c.lineTo(x, y);
    });
    c.lineTo(pad.l + (data.length-1) * xStep, pad.t + ch);
    c.lineTo(pad.l, pad.t + ch);
    c.closePath();
    c.fillStyle = color + '22';
    c.fill();
    // Line
    c.beginPath();
    c.strokeStyle = color;
    c.lineWidth = 2;
    data.forEach((v, i) => {
      const x = pad.l + i * xStep;
      const y = pad.t + ch - ((v - min) / (max - min) * ch);
      i === 0 ? c.moveTo(x, y) : c.lineTo(x, y);
    });
    c.stroke();
    // Dots
    data.forEach((v, i) => {
      const x = pad.l + i * xStep;
      const y = pad.t + ch - ((v - min) / (max - min) * ch);
      c.beginPath(); c.arc(x, y, 3, 0, Math.PI*2);
      c.fillStyle = color; c.fill();
    });
    // Labels
    c.fillStyle = '#4a4a66';
    c.font = '9px monospace';
    c.textAlign = 'center';
    labels.forEach((l, i) => {
      if (data.length <= 4 || i % Math.ceil(data.length/4) === 0) {
        const x = pad.l + i * xStep;
        c.fillText(String(l).slice(0, 8), x, h - 6);
      }
    });
  }
}
